import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { VerificationService } from '../verification.service';
import { AuthService } from '../auth.service';

@Component({
  selector: 'app-notary-dashboard',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './notary-dashboard.component.html',
  styleUrls: ['./notary-dashboard.component.css']
})
export class NotaryDashboardComponent implements OnInit {
  assignedRequests: any[] = [];
  notaryProfile: any = null;
  isLoading: boolean = true;

  constructor(
    private verificationService: VerificationService,
    private authService: AuthService
  ) {}

  ngOnInit() {
    this.loadDashboardData();
  }

  loadDashboardData() {
    // In prototype, mock notary data
    this.notaryProfile = {
      fullName: 'Me. Jean Notaire',
      totalCommissionsEarned: 145000, // XAF
      mobileMoneyNumber: '677 00 00 00',
      missionsCompleted: 23,
      averageRating: 4.8
    };

    // Mock assigned requests
    this.assignedRequests = [
      { id: 'req_1', titleNumber: 'Vol 45 Fol 12', location: 'Yaoundé', status: 'ASSIGNED', fee: 10000 },
      { id: 'req_2', titleNumber: 'Vol 89 Fol 04', location: 'Douala', status: 'ASSIGNED', fee: 10000 }
    ];
    this.isLoading = false;
  }

  formatCurrency(amount: number): string {
    return new Intl.NumberFormat('fr-CM', { style: 'currency', currency: 'XAF' }).format(amount);
  }

  getInitials(name: string): string {
    if (!name) return '';
    return name.replace('Me. ', '').split(' ').map(w => w[0]).join('').toUpperCase();
  }
}
<div class="notary-dashboard">
  <!-- Header: Profile & Wallet -->
  <div class="card" style="display: flex; justify-content: space-between; align-items: center; border-left: 5px solid var(--mt-green); margin-bottom: 2rem;">
    <div>
      <h2 style="margin: 0; color: var(--mt-green);">{{ notaryProfile?.fullName }}</h2>
      <p style="margin: 5px 0 0 0; color: #666;">Portefeuille Notaire : <strong>{{ notaryProfile?.mobileMoneyNumber }}</strong></p>
    </div>
    <div style="text-align: right;">
      <p style="margin: 0; font-size: 0.9rem; color: #888;">COMMISSIONS TOTALES</p>
      <p style="margin: 0; font-size: 1.8rem; font-weight: bold; color: var(--mt-green);">{{ formatCurrency(notaryProfile?.totalCommissionsEarned) }}</p>
      <button class="btn-primary" style="padding: 5px 15px; font-size: 0.8rem; margin-top: 10px; background-color: var(--mt-yellow); color: var(--mt-black);">Retirer via MoMo</button>
    </div>
  </div>

  <!-- Content: Task List -->
  <h3>Missions d'Arbitrage en Attente (Express 48h)</h3>
  
  <div *ngIf="assignedRequests.length === 0" class="card" style="text-align: center; padding: 3rem;">
    <p>Aucune mission en attente pour le moment.</p>
  </div>

  <div *ngIf="assignedRequests.length > 0" style="display: grid; gap: 1rem;">
    <div *ngFor="let req of assignedRequests" class="card" style="display: flex; justify-content: space-between; align-items: center; border-left: 5px solid var(--mt-yellow);">
      <div>
        <h4 style="margin: 0; color: var(--mt-black);">Titre : {{ req.titleNumber }}</h4>
        <p style="margin: 5px 0 0 0; font-size: 0.9rem; color: #666;">📍 {{ req.location }} | Statut: <span style="color: var(--mt-gold); font-weight: bold;">{{ req.status }}</span></p>
      </div>
      <div style="display: flex; align-items: center; gap: 20px;">
        <div style="text-align: right;">
          <p style="margin: 0; font-size: 0.7rem; color: #888;">COMMISSION PRÉVUE</p>
          <p style="margin: 0; font-weight: bold; color: var(--mt-green);">{{ formatCurrency(req.fee * 0.7) }}</p>
        </div>
        <button class="btn-primary">Rédiger le Rapport</button>
      </div>
    </div>
  </div>
</div>
